Code.Terraform:
```hcl
# 在集群使用的 Redshift 参数组中将 require_ssl 设置为 true
resource "aws_redshift_parameter_group" "<example_resource_name>" {
  name   = "<example_resource_name>"
  family = "redshift-1.0"

  parameter {
    name  = "require_ssl"   # 关键：强制客户端连接使用 TLS
    value = "true"          # 关键：启用 SSL 要求
  }
}
```
